.darma-loader-uiverse-pendulum-clock-ball {
  position: relative;
  width: 120px;
  height: 170px;
  background: #ffffff;
  padding-top: 22px;
  border-radius: 25px;
  box-shadow: 5px 5px 0 #666666;
  display: flex;
  flex-direction: column;
  align-items: center;
}
.darma-loader-uiverse-pendulum-clock-ball__clock {
  width: 74px;
  height: 74px;
  border: 6px solid var(--loader-color, #111111);
  border-radius: 50%;
  position: relative;
  background: #f6f6f6;
  box-shadow: inset 0 0 0 4px #ffffff;
}
.darma-loader-uiverse-pendulum-clock-ball__clock::before { content: ""; position: absolute; inset: 33px; background: #111; border-radius: 50%; }
.darma-loader-uiverse-pendulum-clock-ball__clock span { position: absolute; left: 35px; top: 14px; width: 4px; height: 25px; background: #111; transform-origin: 50% 100%; animation: darma-loader-uiverse-pendulum-clock-ball-clockHand 6s linear infinite; }
.darma-loader-uiverse-pendulum-clock-ball__clock span:nth-child(2) { height: 20px; top: 20px; animation-duration: 1.5s; }
.darma-loader-uiverse-pendulum-clock-ball__stage { width: 72px; height: 7px; margin-top: 10px; background: var(--loader-color, #111111); border-radius: 15px; box-shadow: 2px 2px 0 #666666; }
.darma-loader-uiverse-pendulum-clock-ball__hold { width: 3px; height: 56px; background: var(--loader-secondary-color, #32cd32); transform-origin: top center; animation: darma-loader-uiverse-pendulum-clock-ball-dangle 1.3s ease-in-out infinite; box-shadow: 4px 4px 0 #666666; }
.darma-loader-uiverse-pendulum-clock-ball__ball { width: 38px; height: 38px; border-radius: 50%; background: #171717; transform: translate(-17px, 48px); box-shadow: 1px 1px 0 #666666; }
@keyframes darma-loader-uiverse-pendulum-clock-ball-dangle { 0%,100% { transform: rotate(42deg); } 50% { transform: rotate(-42deg); } }
@keyframes darma-loader-uiverse-pendulum-clock-ball-clockHand { to { transform: rotate(360deg); } }

